import { Fixture } from "../../objects/fixture";

interface SeasonSummaryComponentProps{
    fixtures : Fixture[]
}

const SeasonSummary = ({fixtures} : SeasonSummaryComponentProps) => {  

    const totalGames = fixtures.length;
    const totalWins = fixtures.filter(fixture => fixture.result === 0).length;
    const totalDraws = fixtures.filter(fixture => fixture.result === 1).length;
    const totalLosses = fixtures.filter(fixture => fixture.result === 2).length;
    let totalGoals = fixtures.filter(fixture => fixture.glsFor);
    let totalGoalsAgainst = fixtures.filter(fixture => fixture.glsA);
    let goalsDifference = totalGoals - totalGoalsAgainst;
    const totalPoints = fixtures.filter(fixture => fixture.pts).reduce((sum, currentValue) => sum + currentValue.pts, 0);

    return (        
        
        <tr>
            <td>PLD: {totalGames}</td>
            <td>W: {totalWins}</td>
            <td>D: {totalDraws}</td>
            <td>L: {totalLosses}</td>
            <td>GF: {totalGoals}</td>     
            <td>GA: {totalGoalsAgainst}</td>       
            <td>GD: {goalsDifference}</td>
            <td>PTS: {totalPoints}</td>
        </tr>          
    );

}
export default SeasonSummary;
